(1, 'Contáctanos.', 'single-contact', '', '', '', '', '', '', '', '', '<div class=\"row\">\r\n<div class=\"col-md-6 col-sm-6 col-xs-12\">\r\n<p><b>Oficina Centra</b>l<br /> Calle Canamelares N° 426 - Urb. Maranga<br />San Miguel - Lima</p>\r\n<p><b>Horario: </b>De Lunes a Viernes de 9 am. a 6 pm.<br />Sabado de 9 am a 1 pm.</p>\r\n</div>\r\n<div class=\"col-md-6 col-sm-6 col-xs-12\">\r\n<p><b>Oficina Trujillo</b><br /> Urb. Covicorti Mz L. Lt. 23 - Of. 201<br />Trujillo</p>\r\n<p><b>Teléfono:</b> (01) 2647663<br /> <b>Correo:</b> administracion@reingesac.com</p>\r\n</div>\r\n<div id=\"contact-form1\" class=\"contact-form\"><!--p>{loadmodule mod_simplecontact}</p--></div>\r\n</div>', '', 'administracion@reingesac.com', 0, 1, 311, '2022-03-29 11:49:22', 1, '{\"show_contact_category\":\"\",\"show_contact_list\":\"\",\"presentation_style\":\"\",\"show_tags\":\"\",\"show_info\":\"\",\"show_name\":\"\",\"show_position\":\"\",\"show_email\":\"\",\"add_mailto_link\":\"\",\"show_street_address\":\"\",\"show_suburb\":\"\",\"show_state\":\"\",\"show_postcode\":\"\",\"show_country\":\"\",\"show_telephone\":\"\",\"show_mobile\":\"\",\"show_fax\":\"\",\"show_webpage\":\"\",\"show_image\":\"\",\"show_misc\":\"\",\"allow_vcard\":\"\",\"show_articles\":\"\",\"articles_display_num\":\"\",\"show_profile\":\"\",\"show_links\":\"1\",\"linka_name\":\"\",\"linka\":false,\"linkb_name\":\"\",\"linkb\":false,\"linkc_name\":\"\",\"linkc\":false,\"linkd_name\":\"\",\"linkd\":false,\"linke_name\":\"\",\"linke\":false,\"contact_layout\":\"\",\"show_email_form\":\"\",\"show_email_copy\":\"\",\"validate_session\":\"\",\"custom_reply\":\"\",\"redirect\":\"\"}', 0, 4, 1, '', '', '', '', '', '*', '2018-05-02 07:48:31', 311, '', '2022-03-29 11:52:47', 311, '', '', '{\"robots\":\"\",\"rights\":\"\"}', 0, '', '0000-00-00 00:00:00', '0000-00-00 00:00:00', 30, 650);
INSERT INTO `qmdc0_content` (`id`, `asset_id`, `title`, `alias`, `introtext`, `fulltext`, `state`, `catid`, `created`, `created_by`, `created_by_alias`, `modified`, `modified_by`, `checked_out`, `checked_out_time`, `publish_up`, `publish_down`, `images`, `urls`, `attribs`, `version`, `ordering`, `metakey`, `metadesc`, `access`, `hits`, `metadata`, `featured`, `language`, `xreference`, `note`) VALUES
(1, 88, 'About Us', 'about-us', '<div class=\"inner-page-about-property\">\r\n<h1><video controls=\"controls\" width=\"300\" height=\"150\">\r\n<source src=\"/images/VIDEO PAGINA 2021 - II.mp4\" /></video></h1>\r\n<h1>about sabestian villa</h1>\r\n<p class=\"description\">Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed tempor arcu non ligula convallis, vel tincidunt ipsum posuere. Fusce sodales lacus ut pellentesque sollicitudin. Duis iaculis, arcu ut hendrerit pharetra, elit augue pulvinar magna, a consectetur eros quam eu orci. Duis lacus odio, varius tinciduntsit amet, accumsan non ex. Duis id fringilla risus. Donec ac faucibus mauris. Curabitur efficitur gravida ligula.</p>\r\n<ul>\r\n<li>\r\n<figure><img src=\"images/property_icon.png\" alt=\"home\" />\r\n<figcaption>Property Age</figcaption>\r\n</figure>\r\n<h3>Built Year</h3>\r\n<h2>2015</h2>\r\n</li>\r\n<li>\r\n<figure><img src=\"images/sq_ft.png\" alt=\"sqft\" />\r\n<figcaption>IN Sq.ft</figcaption>\r\n</figure>\r\n<h3>area</h3>\r\n<h2>2790</h2>\r\n</li>\r\n<li>\r\n<figure><img src=\"images/bed.png\" alt=\"bed\" />\r\n<figcaption>Number of</figcaption>\r\n</figure>\r\n<h3>Bedroom</h3>\r\n<h2>3</h2>\r\n</li>\r\n<li>\r\n<figure><img class=\"bottom\" src=\"images/bath.png\" alt=\"bathroom\" />\r\n<figcaption>Number of</figcaption>\r\n</figure>\r\n<h3>Bathroom</h3>\r\n<h2>3</h2>\r\n</li>\r\n<li>\r\n<figure><img class=\"bottom\" src=\"images/floor.png\" alt=\"floor\" />\r\n<figcaption>Total</figcaption>\r\n</figure>\r\n<h3>Floors</h3>\r\n<h2>2</h2>\r\n</li>\r\n<li>\r\n<figure><img class=\"bottom\" src=\"images/garage.png\" alt=\"garage\" />\r\n<figcaption>Parking</figcaption>\r\n</figure>\r\n<h3>Garage</h3>\r\n<h2>1</h2>\r\n</li>\r\n</ul>\r\n</div>', '', 1, 2, '2018-04-26 08:29:48', 311, '', '2021-04-25 23:07:09', 311, 0, '0000-00-00 00:00:00', '2018-04-26 08:29:48', '0000-00-00 00:00:00', '{\"image_intro\":\"\",\"float_intro\":\"\",\"image_intro_alt\":\"\",\"image_intro_caption\":\"\",\"image_fulltext\":\"\",\"float_fulltext\":\"\",\"image_fulltext_alt\":\"\",\"image_fulltext_caption\":\"\"}', '{\"urla\":false,\"urlatext\":\"\",\"targeta\":\"\",\"urlb\":false,\"urlbtext\":\"\",\"targetb\":\"\",\"urlc\":false,\"urlctext\":\"\",\"targetc\":\"\"}', '{\"article_layout\":\"\",\"show_title\":\"\",\"link_titles\":\"\",\"show_tags\":\"\",\"show_intro\":\"\",\"info_block_position\":\"\",\"info_block_show_title\":\"\",\"show_category\":\"\",\"link_category\":\"\",\"show_parent_category\":\"\",\"link_parent_category\":\"\",\"show_associations\":\"\",\"show_author\":\"\",\"link_author\":\"\",\"show_create_date\":\"\",\"show_modify_date\":\"\",\"show_publish_date\":\"\",\"show_item_navigation\":\"\",\"show_icons\":\"\",\"show_print_icon\":\"\",\"show_email_icon\":\"\",\"show_vote\":\"\",\"show_hits\":\"\",\"show_noauth\":\"\",\"urls_position\":\"\",\"alternative_readmore\":\"\",\"article_page_title\":\"\",\"show_publishing_options\":\"\",\"show_article_options\":\"\",\"show_urls_images_backend\":\"\",\"show_urls_images_frontend\":\"\"}', 5, 1, '', '', 1, 147, '{\"robots\":\"\",\"author\":\"\",\"rights\":\"\",\"xreference\":\"\"}', 0, '*', '', ''),
(2, 106, 'Quiénes Somos', 'about-us-2', '<p class=\"description\">Somos una empresa sólida, responsable y con experiencia para realizar estudios ambientales y ocupacionales en los diferentes sectores productivos del país. Estamos comprometidos con la protección del medio ambiente, así como con la salud y seguridad de nuestros profesionales, clientes, contratistas y de todos aquellos con quienes nos relacionamos.</p>\r\n<div class=\"row\">\r\n<div class=\"col-lg-6 \">\r\n<div class=\"custom\">\r\n<div id=\"myCarousel\" class=\"slider_div carousel slide\" data-ride=\"carousel\"><!-- Indicators -->\r\n<ol class=\"carousel-indicators\">\r\n<li class=\"\" data-target=\"#myCarousel\" data-slide-to=\"0\"><!--dot--></li>\r\n<li class=\"\" data-target=\"#myCarousel\" data-slide-to=\"1\"><!--dot--></li>\r\n<li class=\"active\" data-target=\"#myCarousel\" data-slide-to=\"2\"><!--dot--></li>\r\n</ol>\r\n<!-- Wrapper for slides -->\r\n<div class=\"carousel-inner\">\r\n<div class=\"item\"><img src=\"images/living_room.jpg\" alt=\"house-image\" /></div>\r\n<div class=\"item\"><img src=\"images/mision.jpg\" alt=\"house-image\" /></div>\r\n<div class=\"item active\"><img src=\"images/vision.jpg\" alt=\"house-image\" /></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-lg-6 \">\r\n<div class=\"custom\">\r\n<ul>\r\n<li>\r\n<div class=\"featureicon pull-left\"><img src=\"images/neghbor-w.png\" alt=\"\" /></div>\r\n<div>\r\n<h2>Nuestra Misión</h2>\r\n<p style=\"text-align: justify;\">Satisfacer las necesidades y expectativas de nuestros clientes dándoles soluciones integrales en servicios ambientales, de seguridad y salud en el trabajo a través de nuestro equipo de técnicos y especialistas en las diferentes disciplinas, y obtengan resultados sustentables en sus negocios a través de la identificación e implementación de soluciones y estrategias ambientales, sociales y de ingeniería eficientes.</p>\r\n</div>\r\n</li>\r\n<li>\r\n<div class=\"featureicon pull-left\"><img src=\"images/furnished-w.png\" alt=\"\" /></div>\r\n<div>\r\n<h2>Nuestra Visión</h2>\r\n<p style=\"text-align: justify;\">Ser una empresa consultora líder a nivel nacional e internacional con tecnología de vanguardia en servicios técnicos y estrategias en el sector de la producción.</p>\r\n</div>\r\n</li>\r\n<li>\r\n<div class=\"featureicon pull-left\"><img src=\"images/furnished-w.png\" alt=\"\" /></div>\r\n<div>\r\n<h2>Valores</h2>\r\n<p style=\"text-align: justify;\">Cultivamos y difundimos valores como: Experiencia, Responsabilidad, Profesionalismo, Trabajo en equipo, Honestidad, Iniciativa, Compromiso, Rentabilidad y confianza, Responsabilidad Social y ambiental, Excelencia e innovación, Entrega de resultados.</p>\r\n</div>\r\n</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>', '', 1, 2, '2018-04-26 08:29:48', 311, '', '2021-03-23 00:51:48', 311, 0, '0000-00-00 00:00:00', '2018-04-26 08:29:48', '0000-00-00 00:00:00', '{\"image_intro\":\"\",\"float_intro\":\"\",\"image_intro_alt\":\"\",\"image_intro_caption\":\"\",\"image_fulltext\":\"\",\"float_fulltext\":\"\",\"image_fulltext_alt\":\"\",\"image_fulltext_caption\":\"\"}', '{\"urla\":false,\"urlatext\":\"\",\"targeta\":\"\",\"urlb\":false,\"urlbtext\":\"\",\"targetb\":\"\",\"urlc\":false,\"urlctext\":\"\",\"targetc\":\"\"}', '{\"article_layout\":\"\",\"show_title\":\"\",\"link_titles\":\"\",\"show_tags\":\"\",\"show_intro\":\"\",\"info_block_position\":\"\",\"info_block_show_title\":\"\",\"show_category\":\"\",\"link_category\":\"\",\"show_parent_category\":\"\",\"link_parent_category\":\"\",\"show_associations\":\"\",\"show_author\":\"\",\"link_author\":\"\",\"show_create_date\":\"\",\"show_modify_date\":\"\",\"show_publish_date\":\"\",\"show_item_navigation\":\"\",\"show_icons\":\"\",\"show_print_icon\":\"\",\"show_email_icon\":\"\",\"show_vote\":\"\",\"show_hits\":\"\",\"show_noauth\":\"\",\"urls_position\":\"\",\"alternative_readmore\":\"\",\"article_page_title\":\"\",\"show_publishing_options\":\"\",\"show_article_options\":\"\",\"show_urls_images_backend\":\"\",\"show_urls_images_frontend\":\"\"}', 7, 0, '', '', 1, 27, '{\"robots\":\"\",\"author\":\"\",\"rights\":\"\",\"xreference\":\"\"}', 0, '*', '', '');
