(91, 59, 'Banner About', '', '<p><img src=\"images/house-banner.jpg\" alt=\"\" /></p>', 5, 'banner-image', 0, '0000-00-00 00:00:00', '2018-04-20 07:22:34', '0000-00-00 00:00:00', 1, 'mod_custom', 1, 0, '{\"prepare_content\":0,\"backgroundimage\":\"\",\"layout\":\"_:default\",\"moduleclass_sfx\":\" banner-aboutproperty\",\"cache\":1,\"cache_time\":900,\"cachemode\":\"static\",\"module_tag\":\"div\",\"bootstrap_size\":\"6\",\"header_tag\":\"h3\",\"header_class\":\"\",\"style\":\"0\"}', 0, '*'),
(92, 60, 'Proyectos', '', '<ul>\r\n<li><label>Declaracion Adecuacion Ambiental </label>FIMA S.A.</li>\r\n<li><label>Declaracion de Impacto Ambiental </label>Almacenes Santa Clara S.A.</li>\r\n<li><label>Informe de Monitoreo Ambiental </label>PVC GERFOR PERU S.A.C.</li>\r\n<li><label>Informe de Identificacion de Sitios Contaminados </label>FUMASA</li>\r\n<li><label>Informe de Monitoreo Ambiental </label>IMC</li>\r\n<li><label>Informe de Monitoreo Ambiental </label>TAL SA Y HORTIFRUT</li>\r\n<li><label>Informe de Plan de Aguas </label>TALSA Y HORTI FRUT</li>\r\n<li><label>Informe Plan de Manejo de Residuos Solidos </label>SIBARITA</li>\r\n<li><label>Informe de Monitoreo Ambiental </label>COTOMAR</li>\r\n<li><label>Capacitaciones en Salud Ocupacional </label>GRAFI MUNDO</li>\r\n<li><label>Capacitaciones en Seguridad y Salud Ocupacional </label>FONDO MIVIVIENDA</li>\r\n<li><label>Declaracion de Adecuacion Ambiental </label>Avantgard College</li>\r\n<li><label>Informe de Monitoreo Ocupacional </label>PROMAS</li>\r\n<li><label>Informe de Monitoreo Ocupacional </label>PVC GERFOR PERU S.A.C</li>\r\n<li><label>Programa de Adecuación y Manejo Ambiental </label>ENVIRONMENT DEVELOPMENT PERÚ</li>\r\n<li><label>Informe de Monitoreo Ambiental </label>CONDUCTORES Y CABLES DEL PERU S.A.C.</li>\r\n</ul>', 2, 'content-bottom', 311, '2021-03-04 16:28:22', '0000-00-00 00:00:00', '0000-00-00 00:00:00', 1, 'mod_custom', 1, 1, '{\"prepare_content\":0,\"backgroundimage\":\"\",\"layout\":\"_:default\",\"moduleclass_sfx\":\" section-dimentions\",\"cache\":1,\"cache_time\":900,\"cachemode\":\"static\",\"module_tag\":\"div\",\"bootstrap_size\":\"0\",\"header_tag\":\"h3\",\"header_class\":\"\",\"style\":\"0\"}', 0, '*'),
(93, 61, 'Quiénes Somos', '', '<p class=\"description\">Somos una empresa sólida, responsable y con experiencia para realizar estudios ambientales y ocupacionales en los diferentes sectores productivos del país. Estamos comprometidos con la protección del medio ambiente, así como con la salud y seguridad de nuestros profesionales, clientes, contratistas y de todos aquellos con quienes nos relacionamos.</p>\r\n<div class=\"row\">\r\n<div class=\"col-lg-6 \">\r\n<div class=\"custom\">\r\n<div id=\"myCarousel\" class=\"slider_div carousel slide\" data-ride=\"carousel\"><!-- Indicators -->\r\n<ol class=\"carousel-indicators\">\r\n<li class=\"\" data-target=\"#myCarousel\" data-slide-to=\"0\"><!--dot--></li>\r\n<li class=\"\" data-target=\"#myCarousel\" data-slide-to=\"1\"><!--dot--></li>\r\n<li class=\"active\" data-target=\"#myCarousel\" data-slide-to=\"2\"><!--dot--></li>\r\n</ol>\r\n<!-- Wrapper for slides -->\r\n<div class=\"carousel-inner\">\r\n<div class=\"item\"><img src=\"images/living_room.jpg\" alt=\"house-image\" /></div>\r\n<div class=\"item\"><img src=\"images/mision.jpg\" alt=\"house-image\" /></div>\r\n<div class=\"item active\"><img src=\"images/vision.jpg\" alt=\"house-image\" /></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-lg-6 \">\r\n<div class=\"custom\">\r\n<ul>\r\n<li>\r\n<div class=\"featureicon pull-left\"><img src=\"images/neghbor-w.png\" alt=\"\" /></div>\r\n<div>\r\n<h2>Nuestra Misión</h2>\r\n<p style=\"text-align: justify;\">Satisfacer las necesidades y expectativas de nuestros clientes dándoles soluciones integrales en servicios ambientales, de seguridad y salud en el trabajo a través de nuestro equipo de técnicos y especialistas en las diferentes disciplinas, y obtengan resultados sustentables en sus negocios a través de la identificación e implementación de soluciones y estrategias ambientales, sociales y de ingeniería eficientes.</p>\r\n</div>\r\n</li>\r\n<li>\r\n<div class=\"featureicon pull-left\"><img src=\"images/furnished-w.png\" alt=\"\" /></div>\r\n<div>\r\n<h2>Nuestra Visión</h2>\r\n<p style=\"text-align: justify;\">Ser una empresa consultora líder a nivel nacional e internacional con tecnología de vanguardia en servicios técnicos y estrategias en los diferentes sectores productivos.</p>\r\n</div>\r\n</li>\r\n<li>\r\n<div class=\"featureicon pull-left\"><img src=\"images/valores-w.png\" alt=\"\" /></div>\r\n<div>\r\n<h2>Valores</h2>\r\n<p style=\"text-align: justify;\">Cultivamos y difundimos valores como: Experiencia, Responsabilidad, Profesionalismo, Trabajo en equipo, Honestidad, Iniciativa, Compromiso, Rentabilidad y confianza, Responsabilidad Social y ambiental, Excelencia e innovación, Entrega de resultados.</p>\r\n</div>\r\n</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>', 1, 'content-bottom', 0, '0000-00-00 00:00:00', '0000-00-00 00:00:00', '0000-00-00 00:00:00', 1, 'mod_custom', 1, 1, '{\"prepare_content\":0,\"backgroundimage\":\"\",\"layout\":\"_:default\",\"moduleclass_sfx\":\" section-features\",\"cache\":1,\"cache_time\":900,\"cachemode\":\"static\",\"module_tag\":\"div\",\"bootstrap_size\":\"0\",\"header_tag\":\"h3\",\"header_class\":\"\",\"style\":\"0\"}', 0, '*'),
(96, 64, 'Test', '', '<p>Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation</p>', 1, 'test', 0, '0000-00-00 00:00:00', '2018-04-19 10:11:01', '0000-00-00 00:00:00', 1, 'mod_custom', 1, 1, '{\"prepare_content\":\"0\",\"backgroundimage\":\"\",\"layout\":\"_:default\",\"moduleclass_sfx\":\" section-test\",\"cache\":\"1\",\"cache_time\":\"900\",\"cachemode\":\"static\",\"module_tag\":\"div\",\"bootstrap_size\":\"0\",\"header_tag\":\"h3\",\"header_class\":\"\",\"style\":\"0\"}', 0, '*'),
